def create_llm_model(config: LLMConfig) -> OpenAIChatModel:
    """Create pydantic-ai model with Yandex transport."""
    transport = YandexHTTPTransport(verify=False)
    http_client = httpx.AsyncClient(transport=transport)

    provider = OpenAIProvider(
        base_url=config.base_url,
        api_key=config.api_key,
        http_client=http_client,
    )

    return OpenAIChatModel(config.model, provider=provider)

class QdrantVectorStore:
    """Qdrant vector store service."""

    def __init__(self, config: QdrantConfig, vector_size: int = 1536) -> None:
        self.config = config
        self.vector_size = vector_size
        self.client = AsyncQdrantClient(
            url=config.url,
            api_key=config.api_key,
        )

class SimpleEventBus:
    """In-memory event bus implementation."""

    def __init__(self) -> None:
        self._events: list[dict] = []
        self.logger = get_logger(__name__)

    async def emit(self, event_type: str, data: dict) -> None:
        """Emit an event."""
        event = {
            "type": event_type,
            "data": data,
        }
        self._events.append(event)
        self.logger.info("event_emitted", event_type=event_type)
